import React from 'react';
import VideoBackground from "../VideoBackground/VideoBackground";
import './StudentPage.css'; // Vom crea acest CSS
import Assignments from "../Assignments/Assignments";

const StudentPage: React.FC = () => {
    const username = localStorage.getItem('username') || 'Student';

    return (
        <div className="student-page-container">
            <VideoBackground />
            <div className="content-box">
                <h1>Bine ai venit, Studentule {username}!</h1>
                <p>Aici va fi panoul tău de student.</p>
                {/* Aici poți adăuga link-uri către Teme, Note etc. */}
                <div className="navigation-buttons">
                    <Link to="/teme" className="nav-action-button">
                        Teme
                    </Link>
                    <Link to="/teste" className="nav-action-button">
                        Teste
                    </Link>
                </div>
            </div>
        </div>
    );
};

export default StudentPage;
